import heapq
class Solution:
    def isPossible(self, nums):
        # Greedy by smallest open-chain length: each value either extends the
        # shortest chain ending at value-1 or opens a new chain. At the end
        # every chain must have length >= 3.
        chains = {}
        for x in sorted(nums):
            prev = chains.get(x - 1)
            if prev:
                length = heapq.heappop(prev)
                if not prev:
                    del chains[x - 1]
                chains.setdefault(x, [])
                heapq.heappush(chains[x], length + 1)
            else:
                chains.setdefault(x, [])
                heapq.heappush(chains[x], 1)
        for heap in chains.values():
            for length in heap:
                if length < 3:
                    return False
        return True

