class Solution:
    def isPossible(self, nums):
        from collections import Counter, defaultdict
        count = Counter(nums)
        ends = defaultdict(int)
        for x in nums:
            if count[x] == 0:
                continue
            if ends[x - 1] > 0:
                ends[x - 1] -= 1
                ends[x] += 1
                count[x] -= 1
            elif count[x + 1] > 0 and count[x + 2] > 0:
                count[x] -= 1
                count[x + 1] -= 1
                count[x + 2] -= 1
                ends[x + 2] += 1
            else:
                return False
        return True

