var isPossible = function(nums) {
    const count = new Map();
    const ends = new Map();
    const get = (m, k) => m.get(k) || 0;
    for (const x of nums) count.set(x, get(count, x) + 1);
    for (const x of nums) {
        if (get(count, x) === 0) continue;
        if (get(ends, x - 1) > 0) {
            ends.set(x - 1, get(ends, x - 1) - 1);
            ends.set(x, get(ends, x) + 1);
            count.set(x, get(count, x) - 1);
        } else if (get(count, x + 1) > 0 && get(count, x + 2) > 0) {
            count.set(x, get(count, x) - 1);
            count.set(x + 1, get(count, x + 1) - 1);
            count.set(x + 2, get(count, x + 2) - 1);
            ends.set(x + 2, get(ends, x + 2) + 1);
        } else {
            return false;
        }
    }
    return true;
};
